// Helper function to create a 2D array from a string representation
int** create_matrix_from_json_string(const std::string& input_str, int& rows, int& cols) {
    if (input_str == "NULL_MATRIX") {
        return nullptr;
    }

    std::vector<std::vector<int>> data;
    if (input_str.length() > 2) { // Check if it's not just "[]"
        std::string cleaned_input = input_str.substr(1, input_str.length() - 2); // Remove outer brackets
        std::regex row_regex("\[([^\]]*)\]");
        auto words_begin = std::sregex_iterator(cleaned_input.begin(), cleaned_input.end(), row_regex);
        auto words_end = std::sregex_iterator();

        for (std::sregex_iterator i = words_begin; i != words_end; ++i) {
            std::smatch match = *i;
            std::string row_str = match[1].str(); // Content inside inner brackets
            std::vector<int> row;
            if (!row_str.empty()) {
                std::stringstream rss(row_str);
                int val;
                char comma;
                while (rss >> val) {
                    row.push_back(val);
                    if (rss.peek() == ',') {
                        rss >> comma;
                    }
                }
            }
            data.push_back(row);
        }
    }

    if (data.empty()) {
        rows = 0;
        cols = 0;
        return nullptr;
    }

    rows = data.size();
    cols = data[0].size(); // Assume consistent column sizes for valid inputs
    // Handle case where all inner vectors are empty, meaning 0 columns
    if (rows > 0 && cols == 0) {
        bool all_rows_empty = true;
        for (const auto& r_vec : data) {
            if (!r_vec.empty()) {
                all_rows_empty = false;
                break;
            }
        }
        if (!all_rows_empty) { // If not all rows are empty, then something is wrong with cols=0 assumption
            // This case should ideally not happen with well-formed test data.
            // For now, assume cols is correctly 0 if all rows are empty.
        }
    }

    int** matrix = new int*[rows];
    for (int i = 0; i < rows; ++i) {
        matrix[i] = new int[cols];
        for (int j = 0; j < cols; ++j) {
            matrix[i][j] = data[i][j];
        }
    }
    return matrix;
}

// Helper function to delete a 2D array
void delete_matrix(int** matrix, int rows) {
    if (matrix) {
        for (int i = 0; i < rows; ++i) {
            delete[] matrix[i]; 
        }
        delete[] matrix;
    }
}

